<?php
namespace App\Domain\Loot;use App\Domain\Inventory\ItemClassification;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use InvalidArgumentException;
final class LootConfigurationValidator{private $classification;public function __construct(ItemClassification $classification){$this->classification=$classification;}public function validate(Monster $m,Item $i,int $probabilityPpm,int $min,int $max,string $status,MonsterLootEntry $existing=null):void{if(!$m->exists||!$i->exists)throw new InvalidArgumentException('References must be persisted.');$kind=$this->classification->classify($i);if($probabilityPpm<0||$probabilityPpm>1000000||$min<1||$max<$min||$min>PHP_INT_MAX||$max>PHP_INT_MAX)throw new InvalidArgumentException('Invalid loot values.');if($kind===ItemClassification::UNIQUE&&($min!==1||$max!==1))throw new InvalidArgumentException('Non-stackable loot requires minimum and maximum quantity equal to 1.');if(!in_array($status,CatalogStatus::values(),true))throw new InvalidArgumentException('Invalid status.');if($existing&&(int)$existing->monster_id!==(int)$m->id)throw new InvalidArgumentException('Existing entry mismatch.');$q=MonsterLootEntry::where('monster_id',$m->id)->where('item_id',$i->id);if($existing)$q->where('id','<>',$existing->id);if($q->exists())throw new InvalidArgumentException('Duplicate loot entry.');}}
